export enum AnalysisStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

export interface AnalysisState {
  status: AnalysisStatus;
  result: string | null;
  error: string | null;
}

export interface FileData {
  file: File;
  previewUrl: string;
  type: 'video' | 'audio';
}

export interface TimelineEvent {
  time: string;
  label: string;
}

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT, MODEL_NAME } from '../constants';

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove the data URL prefix (e.g., "data:video/mp4;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeUserSession = async (file: File): Promise<string> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key not found in environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const base64Data = await fileToBase64(file);

    // Determine mime type broadly or specifically
    const mimeType = file.type;

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          {
            text: SYSTEM_PROMPT
          }
        ]
      },
      config: {
        thinkingConfig: { thinkingBudget: 4096 } // Enable thinking for better analysis
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No analysis generated from the model.");
    }
    return text;

  } catch (error: any) {
    console.error("Gemini Analysis Error:", error);
    throw new Error(error.message || "Failed to analyze the session.");
  }
};

import React, { useRef, useState } from 'react';
import { Upload, FileAudio, FileVideo, AlertCircle } from 'lucide-react';
import { MAX_FILE_SIZE_MB } from '../constants';

interface UploadSectionProps {
  onFileSelected: (file: File) => void;
  isLoading: boolean;
}

export const UploadSection: React.FC<UploadSectionProps> = ({ onFileSelected, isLoading }) => {
  const [dragActive, setDragActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleFiles = (files: FileList | null) => {
    if (!files || files.length === 0) return;

    const file = files[0];
    const fileSizeMB = file.size / (1024 * 1024);

    if (fileSizeMB > MAX_FILE_SIZE_MB) {
      setError(`File size exceeds ${MAX_FILE_SIZE_MB}MB limit for this demo.`);
      return;
    }

    if (!file.type.startsWith('video/') && !file.type.startsWith('audio/')) {
      setError("Please upload a valid Video (MP4) or Audio (MP3) file.");
      return;
    }

    setError(null);
    onFileSelected(file);
  };

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFiles(e.dataTransfer.files);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files) {
      handleFiles(e.target.files);
    }
  };

  const onButtonClick = () => {
    inputRef.current?.click();
  };

  return (
    <div className="w-full max-w-2xl mx-auto mt-10 p-6">
      <div 
        className={`
          relative flex flex-col items-center justify-center w-full h-80 
          rounded-2xl border-2 border-dashed transition-all duration-300 ease-in-out
          ${dragActive 
            ? "border-indigo-500 bg-indigo-500/10 scale-[1.02]" 
            : "border-slate-600 bg-slate-800/50 hover:bg-slate-800 hover:border-slate-500"
          }
          ${isLoading ? "opacity-50 pointer-events-none" : "cursor-pointer"}
        `}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
        onClick={onButtonClick}
      >
        <input
          ref={inputRef}
          type="file"
          className="hidden"
          accept="video/*,audio/*"
          onChange={handleChange}
          disabled={isLoading}
        />

        <div className="flex flex-col items-center text-center p-6 space-y-4">
          <div className="p-4 rounded-full bg-slate-700/50 text-indigo-400">
            <Upload size={40} strokeWidth={1.5} />
          </div>

          <div className="space-y-1">
            <h3 className="text-xl font-semibold text-slate-100">
              Upload Session Recording
            </h3>
            <p className="text-sm text-slate-400">
              Drag & drop or click to browse
            </p>
          </div>

          <div className="flex items-center gap-4 text-xs text-slate-500 font-medium">
            <span className="flex items-center gap-1.5 bg-slate-800/80 px-3 py-1.5 rounded-full border border-slate-700">
              <FileVideo size={14} /> MP4, WEBM
            </span>
            <span className="flex items-center gap-1.5 bg-slate-800/80 px-3 py-1.5 rounded-full border border-slate-700">
              <FileAudio size={14} /> MP3, WAV
            </span>
          </div>
        </div>

        {dragActive && (
          <div className="absolute inset-0 rounded-2xl bg-indigo-500/10 flex items-center justify-center backdrop-blur-sm">
            <p className="text-lg font-semibold text-indigo-300">Drop file to analyze</p>
          </div>
        )}
      </div>

      {error && (
        <div className="mt-4 flex items-center gap-2 text-red-400 bg-red-900/20 p-3 rounded-lg border border-red-900/50">
          <AlertCircle size={18} />
          <span className="text-sm font-medium">{error}</span>
        </div>
      )}
    </div>
  );
};

