import React, { useState, useEffect } from 'react';
import { UploadSection } from './components/UploadSection';
import { AnalysisView } from './components/AnalysisView';
import { analyzeUserSession } from './services/gemini';
import { AnalysisState, AnalysisStatus, FileData } from './types';
import { BrainCircuit, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [analysisState, setAnalysisState] = useState<AnalysisState>({
    status: AnalysisStatus.IDLE,
    result: null,
    error: null,
  });

  const handleFileSelected = (file: File) => {
    const url = URL.createObjectURL(file);
    setFileData({
      file,
      previewUrl: url,
      type: file.type.startsWith('video') ? 'video' : 'audio',
    });

    // Auto-start analysis
    startAnalysis(file);
  };

  const startAnalysis = async (file: File) => {
    setAnalysisState({
      status: AnalysisStatus.PROCESSING,
      result: null,
      error: null,
    });

    try {
      const result = await analyzeUserSession(file);
      setAnalysisState({
        status: AnalysisStatus.COMPLETED,
        result,
        error: null,
      });
    } catch (error: any) {
      setAnalysisState({
        status: AnalysisStatus.ERROR,
        result: null,
        error: error.message || "An error occurred during analysis.",
      });
    }
  };

  const handleReset = () => {
    if (fileData?.previewUrl) {
      URL.revokeObjectURL(fileData.previewUrl);
    }
    setFileData(null);
    setAnalysisState({
      status: AnalysisStatus.IDLE,
      result: null,
      error: null,
    });
  };

  // Cleanup URLs on unmount
  useEffect(() => {
    return () => {
      if (fileData?.previewUrl) {
        URL.revokeObjectURL(fileData.previewUrl);
      }
    };
  }, [fileData]);

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-50 flex flex-col">
      {/* Header */}
      <header className="border-b border-slate-800 bg-[#0f172a]/80 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2.5">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <BrainCircuit className="text-white" size={24} />
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight text-white leading-none">
                Research<span className="text-indigo-400">Synthesizer</span>
              </h1>
              <p className="text-[10px] text-slate-400 font-medium tracking-wide uppercase mt-0.5">
                UX Observation AI
              </p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-2 text-xs font-medium text-slate-400 bg-slate-800/50 px-3 py-1.5 rounded-full border border-slate-700">
            <Sparkles size={12} className="text-indigo-400" />
            <span>Powered by Gemini 3.0 Pro</span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col">
        {!fileData ? (
          <div className="flex-1 flex flex-col items-center justify-center p-6 animate-fade-in">
            <div className="text-center max-w-2xl mx-auto mb-8">
              <h2 className="text-3xl md:text-4xl font-bold text-white mb-4">
                Turn Interviews into Insights <br/> 
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-cyan-400">
                  in Seconds
                </span>
              </h2>
              <p className="text-slate-400 text-lg">
                Upload your raw user testing video or audio. Get a structured friction report, 
                sentiment map, and heuristic analysis instantly.
              </p>
            </div>

            <UploadSection 
              onFileSelected={handleFileSelected} 
              isLoading={false} 
            />

            <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-6 max-w-4xl w-full text-center px-4">
              <div className="p-4 rounded-xl bg-slate-800/30 border border-slate-800">
                <div className="text-indigo-400 font-bold text-xl mb-1">40%</div>
                <div className="text-slate-500 text-sm">Time Saved per Study</div>
              </div>
              <div className="p-4 rounded-xl bg-slate-800/30 border border-slate-800">
                <div className="text-indigo-400 font-bold text-xl mb-1">0%</div>
                <div className="text-slate-500 text-sm">Subjective Bias</div>
              </div>
              <div className="p-4 rounded-xl bg-slate-800/30 border border-slate-800">
                <div className="text-indigo-400 font-bold text-xl mb-1">100%</div>
                <div className="text-slate-500 text-sm">Verifiable Quotes</div>
              </div>
            </div>
          </div>
        ) : (
          <AnalysisView 
            fileData={fileData} 
            analysisState={analysisState} 
            onReset={handleReset}
            onRetry={() => startAnalysis(fileData.file)}
          />
        )}
      </main>

      <footer className="py-6 text-center text-slate-600 text-sm border-t border-slate-800/50">
        <p>&copy; {new Date().getFullYear()} ResearchSynthesizer AI. Designed for Senior UX Researchers.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { X, Check, Download, Share2, Lock } from 'lucide-react';

interface ExportModalProps {
  isOpen: boolean;
  onClose: () => void;
  content: string;
}

type Platform = 'notion' | 'jira' | 'confluence' | 'trello' | 'csv';

export const ExportModal: React.FC<ExportModalProps> = ({ isOpen, onClose, content }) => {
  const [platform, setPlatform] = useState<Platform>('notion');
  const [apiKey, setApiKey] = useState('');
  const [instanceUrl, setInstanceUrl] = useState('');
  const [isExporting, setIsExporting] = useState(false);
  const [success, setSuccess] = useState(false);

  if (!isOpen) return null;

  const handleExport = (e: React.FormEvent) => {
    e.preventDefault();
    setIsExporting(true);

    // Simulate API call to external platform
    setTimeout(() => {
      setIsExporting(false);
      setSuccess(true);

      // Fallback: Copy to clipboard or download based on platform
      if (platform === 'csv') {
        // Simple download trigger for demo purposes
        const blob = new Blob([content], { type: 'text/markdown' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'research-synthesis.md';
        a.click();
      } else {
        navigator.clipboard.writeText(content);
      }

      setTimeout(() => {
        setSuccess(false);
        onClose();
      }, 2000);
    }, 1500);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden transform transition-all scale-100">

