          <button 
            onClick={onClose}
            className="text-slate-400 hover:text-white transition-colors"
          >
            <X size={20} />
          </button>
        </div>

        {/* Body */}
        <form onSubmit={handleExport} className="p-6 space-y-5">
          <div className="space-y-2">
            <label className="text-xs font-medium text-slate-400 uppercase tracking-wide">Destination Platform</label>
            <div className="grid grid-cols-2 gap-3">
              {(['notion', 'jira', 'confluence', 'trello'] as Platform[]).map((p) => (
                <button
                  key={p}
                  type="button"
                  onClick={() => setPlatform(p)}
                  className={`
                    px-4 py-3 rounded-xl border text-sm font-medium capitalize transition-all flex items-center justify-center gap-2
