                <label className="text-xs font-medium text-slate-400 flex items-center gap-1">
                  Instance URL <span className="text-red-400">*</span>
                </label>
                <input 
                  type="url" 
                  placeholder={`https://your-company.${platform}.com`}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2.5 text-sm text-white placeholder-slate-600 focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-colors"
                  value={instanceUrl}
                  onChange={(e) => setInstanceUrl(e.target.value)}
                  required
                />
             </div>

             <div className="space-y-1.5">
                <label className="text-xs font-medium text-slate-400 flex items-center gap-1">
                  API Token / Auth Key <Lock size={10} /> <span className="text-red-400">*</span>
                </label>
                <input 
                  type="password" 
                  placeholder="sk-..."
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2.5 text-sm text-white placeholder-slate-600 focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-colors"
                  value={apiKey}
                  onChange={(e) => setApiKey(e.target.value)}
                  required
                />
             </div>
          </div>

          <div className="pt-4">
            <button
              type="submit"
              disabled={isExporting || success}
              className={`
                w-full py-3 rounded-xl text-sm font-semibold text-white shadow-lg transition-all flex items-center justify-center gap-2
                ${success 
                  ? "bg-green-600 hover:bg-green-700" 
                  : "bg-gradient-to-r from-indigo-600 to-indigo-500 hover:from-indigo-500 hover:to-indigo-400"
                }
                ${isExporting ? "opacity-75 cursor-wait" : ""}
              `}
            >
              {isExporting ? (
                <>Moving Data...</>
              ) : success ? (
