              <h3 className="text-xl font-bold text-slate-900">Synthesizing...</h3>
              <p className="text-slate-500 mt-2 font-medium">
                Identifying speakers, friction points, and recurring themes.
              </p>
            </div>

            <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden relative z-10">
               <div className="h-full bg-orange-500 w-1/3 animate-[shimmer_1.5s_infinite_linear] bg-[length:200%_100%] bg-gradient-to-r from-orange-400 via-orange-300 to-orange-400"></div>
            </div>
          </div>
        )}

        {/* Error State Card */}
        {isError && (
          <div className="bg-red-50 border border-red-100 rounded-3xl p-8 flex flex-col items-center text-center space-y-4">
            <div className="p-4 bg-white rounded-full text-red-500 shadow-sm">
              <AlertTriangle size={28} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-red-700">Analysis Failed</h3>
              <p className="text-sm text-red-600/80 mt-1 font-medium">
                {analysisState.error || "An unexpected error occurred during synthesis."}
              </p>
            </div>
            <button 
              onClick={onRetry}
              className="px-6 py-2.5 bg-red-600 hover:bg-red-700 text-white rounded-xl text-sm font-bold transition-all shadow-md shadow-red-200"
            >
              Retry Analysis
            </button>
          </div>
        )}

        {/* Tips / Instructions */}
        {!isCompleted && !isProcessing && !isError && (
           <div className="bg-white border border-slate-100 rounded-3xl p-6 shadow-sm">
             <div className="flex items-center gap-2 mb-4">
                <span className="bg-purple-100 text-purple-700 px-3 py-1 rounded-lg text-xs font-bold uppercase tracking-wider">Capabilities</span>
             </div>
             <ul className="space-y-4 text-sm font-medium text-slate-600">
               <li className="flex items-start gap-3 p-2 rounded-lg hover:bg-slate-50 transition-colors">
                 <div className="mt-0.5 bg-indigo-100 p-1 rounded-md text-indigo-600">
                    <ChevronRight size={14} strokeWidth={3} />
                 </div>
                 <span><b>Speaker Diarization:</b> Automatically distinguishes between Interviewer and User.</span>
               </li>
               <li className="flex items-start gap-3 p-2 rounded-lg hover:bg-slate-50 transition-colors">
                 <div className="mt-0.5 bg-pink-100 p-1 rounded-md text-pink-600">
                    <ChevronRight size={14} strokeWidth={3} />
                 </div>
                 <span><b>Thematic Analysis:</b> Summarizes overarching patterns and recurring topics.</span>
               </li>
               <li className="flex items-start gap-3 p-2 rounded-lg hover:bg-slate-50 transition-colors">
                 <div className="mt-0.5 bg-green-100 p-1 rounded-md text-green-600">
                    <ChevronRight size={14} strokeWidth={3} />
                 </div>
                 <span><b>Friction Mapping:</b> Exact quotes and timestamps mapped to Usability Heuristics.</span>
               </li>
             </ul>
           </div>
        )}
      </div>

      {/* Right Column: Analysis Output (7 columns) */}
      <div className="lg:col-span-7 flex flex-col h-[600px] lg:h-auto min-h-[500px]">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
             <div className="bg-orange-100 p-2 rounded-xl">
                 <FileText className="text-orange-600" size={20} />
             </div>
             <h2 className="text-2xl font-bold text-slate-900">
                Research Insights
             </h2>
          </div>

          {isCompleted && (
            <div className="flex items-center gap-3">
                <button
                onClick={() => setIsExportModalOpen(true)}
                className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold bg-orange-500 text-white hover:bg-orange-600 transition-all shadow-lg shadow-orange-500/20 transform hover:-translate-y-0.5"
                >
                <Share size={16} strokeWidth={2.5} /> Export
                </button>
                <div className="flex bg-white rounded-xl border border-slate-200 p-1 shadow-sm">
                    <button
                        onClick={handleDownload}
                        className="p-2 rounded-lg text-slate-500 hover:text-slate-900 hover:bg-slate-50 transition-colors"
                        title="Download Markdown"
                    >
                        <Download size={18} />
                    </button>
                    <div className="w-px bg-slate-200 mx-1 my-1"></div>
                    <button
                        onClick={handleCopy}
                        className={`
                        p-2 rounded-lg transition-colors flex items-center gap-1
                        ${copied 
                            ? "text-green-600 bg-green-50" 
                            : "text-slate-500 hover:text-slate-900 hover:bg-slate-50"
                        }
                        `}
                        title="Copy to Clipboard"
                    >
                        {copied ? <Check size={18} /> : <Copy size={18} />}
                    </button>
                </div>
            </div>
          )}
        </div>

        <div className={`
          flex-1 bg-white rounded-3xl border border-slate-100 shadow-[0_4px_20px_-4px_rgba(0,0,0,0.05)] overflow-hidden relative
          ${!isCompleted ? "flex items-center justify-center" : ""}
        `}>
          {isCompleted ? (
            <div className="h-full overflow-y-auto p-8 custom-scrollbar">
              <div className="markdown-body">
                <ReactMarkdown>{analysisState.result || ''}</ReactMarkdown>
              </div>
            </div>
          ) : (
            <div className="text-center p-8 max-w-sm">
              <div className="w-20 h-20 bg-slate-50 rounded-3xl rotate-3 flex items-center justify-center mx-auto mb-6 border-2 border-slate-100 text-slate-300 shadow-sm">
                <FileText size={40} />
              </div>
              <h4 className="text-slate-900 font-bold text-lg mb-2">Ready to Analyze</h4>
              <p className="text-slate-500 font-medium">
                {isProcessing ? "Synthesizing themes & separating speakers..." : "Upload a session recording to generate a detailed report."}
              </p>
            </div>
          )}
        </div>
      </div>

      <ExportModal 
        isOpen={isExportModalOpen} 
        onClose={() => setIsExportModalOpen(false)} 
        content={analysisState.result || ''} 
      />
    </div>
  );
};

import React, { useState } from 'react';
import { X, Check, Download, Share2, Lock } from 'lucide-react';

interface ExportModalProps {
  isOpen: boolean;
  onClose: () => void;
  content: string;
}

type Platform = 'notion' | 'jira' | 'confluence' | 'trello' | 'csv';

export const ExportModal: React.FC<ExportModalProps> = ({ isOpen, onClose, content }) => {
  const [platform, setPlatform] = useState<Platform>('notion');
  const [apiKey, setApiKey] = useState('');
  const [instanceUrl, setInstanceUrl] = useState('');
  const [isExporting, setIsExporting] = useState(false);
  const [success, setSuccess] = useState(false);

  if (!isOpen) return null;

  const handleExport = (e: React.FormEvent) => {
    e.preventDefault();
    setIsExporting(true);

    // Simulate API call to external platform
    setTimeout(() => {
      setIsExporting(false);
      setSuccess(true);

      // Fallback: Copy to clipboard or download based on platform
      if (platform === 'csv') {
        const blob = new Blob([content], { type: 'text/markdown' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'research-synthesis.md';
        a.click();
      } else {
        navigator.clipboard.writeText(content);
      }

      setTimeout(() => {
        setSuccess(false);
        onClose();
      }, 2000);
    }, 1500);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-fade-in">
      <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden transform transition-all scale-100 border border-slate-100">

        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-slate-100 bg-white">
          <h3 className="text-lg font-bold text-slate-900 flex items-center gap-2">
            <div className="bg-orange-100 p-1.5 rounded-lg text-orange-600">
               <Share2 size={18} strokeWidth={2.5} />
            </div>
            Export Insights
          </h3>
          <button 
            onClick={onClose}
            className="text-slate-400 hover:text-slate-900 bg-slate-50 hover:bg-slate-100 p-2 rounded-full transition-all"
          >
            <X size={18} />
          </button>
        </div>

        {/* Body */}
        <form onSubmit={handleExport} className="p-8 space-y-6">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Destination Platform</label>
            <div className="grid grid-cols-2 gap-3">
              {(['notion', 'jira', 'confluence', 'trello'] as Platform[]).map((p) => (
                <button
                  key={p}
                  type="button"
                  onClick={() => setPlatform(p)}
                  className={`
                    px-4 py-3.5 rounded-2xl border text-sm font-bold capitalize transition-all flex items-center justify-center gap-2
                    ${platform === p 
                      ? "bg-orange-50 border-orange-200 text-orange-700 shadow-sm" 
                      : "bg-white border-slate-100 text-slate-500 hover:bg-slate-50 hover:border-slate-200"
                    }
                  `}
                >
                  {p}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
             <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 flex items-center gap-1 ml-1">
                  Instance URL <span className="text-red-500">*</span>
                </label>
                <input 
                  type="url" 
                  placeholder={`https://your-company.${platform}.com`}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm text-slate-900 placeholder-slate-400 focus:outline-none focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all font-medium"
                  value={instanceUrl}
                  onChange={(e) => setInstanceUrl(e.target.value)}
                  required
                />
             </div>

             <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 flex items-center gap-1 ml-1">
                  API Token <Lock size={12} /> <span className="text-red-500">*</span>
                </label>
                <input 
                  type="password" 
                  placeholder="sk-..."
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm text-slate-900 placeholder-slate-400 focus:outline-none focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all font-medium"
                  value={apiKey}
                  onChange={(e) => setApiKey(e.target.value)}
                  required
                />
             </div>
          </div>

          <div className="pt-2">
            <button
              type="submit"
              disabled={isExporting || success}
              className={`
                w-full py-3.5 rounded-xl text-sm font-bold text-white shadow-lg shadow-orange-500/20 transition-all flex items-center justify-center gap-2 transform active:scale-95
                ${success 
                  ? "bg-green-500 hover:bg-green-600 shadow-green-500/20" 
                  : "bg-orange-500 hover:bg-orange-600"
                }
                ${isExporting ? "opacity-75 cursor-wait" : ""}
              `}
            >
              {isExporting ? (
                <>Moving Data...</>
              ) : success ? (
                <><Check size={18} strokeWidth={3} /> Exported Successfully</>
              ) : (
                <>Connect & Export</>
              )}
            </button>
            <p className="text-[10px] text-slate-400 text-center mt-4 font-medium">
              Data is formatted specifically for the target platform's markup.
            </p>
          </div>
        </form>
      </div>
    </div>
  );
};
